import { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate, Link } from 'react-router-dom';
import { register } from '../features/auth/authSlice';

export default function RegisterPage() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { loading, error } = useSelector(s => s.auth);
  const [form, setForm] = useState({ name: '', email: '', password: '' });

  const handleSubmit = async e => {
    e.preventDefault();
    const res = await dispatch(register(form));
    if (!res.error) navigate('/');
  };

  return (
    <div style={styles.wrap}>
      <form onSubmit={handleSubmit} style={styles.card}>
        <h2 style={styles.title}>Create Account</h2>
        {error && <p style={styles.error}>{error}</p>}
        <input style={styles.input} placeholder="Full Name" value={form.name}
          onChange={e => setForm({ ...form, name: e.target.value })} required />
        <input style={styles.input} placeholder="Email" type="email" value={form.email}
          onChange={e => setForm({ ...form, email: e.target.value })} required />
        <input style={styles.input} placeholder="Password" type="password" value={form.password}
          onChange={e => setForm({ ...form, password: e.target.value })} required />
        <button style={styles.btn} disabled={loading}>{loading ? 'Creating...' : 'Register'}</button>
        <p style={{ textAlign: 'center', marginTop: 12 }}>
          Have an account? <Link to="/login">Login</Link>
        </p>
      </form>
    </div>
  );
}

const styles = {
  wrap:  { display:'flex', justifyContent:'center', alignItems:'center', minHeight:'80vh', background:'#f5f5f5' },
  card:  { background:'#fff', padding:'32px', borderRadius:'8px', width:'360px', boxShadow:'0 2px 12px rgba(0,0,0,0.1)', display:'flex', flexDirection:'column', gap:'12px' },
  title: { margin:0, textAlign:'center', color:'#1a1a2e' },
  input: { padding:'10px', border:'1px solid #ddd', borderRadius:'4px', fontSize:'1rem' },
  btn:   { padding:'10px', background:'#e94560', color:'#fff', border:'none', borderRadius:'4px', cursor:'pointer', fontSize:'1rem' },
  error: { color:'red', margin:0, textAlign:'center' },
};
